    "level": 55,
    "high_confidence_areas": [
      "Timeout mismatch between CartService and PaymentService is a definite bug — 5s < 8s is objectively broken",
      "Missing compensation for Order→Payment failure sequence is a guaranteed data consistency issue",
      "Circuit breaker coverage gaps are clear from the spec"
    ],
